pipeline.evaluate:
(() => {
  const input = '${{ args.url }}';
  let videoId = input;
  if (input.startsWith('http')) {
    try {
      const parsed = new URL(input);
      if (parsed.searchParams.has('v')) videoId = parsed.searchParams.get('v');
      else if (parsed.hostname === 'youtu.be') videoId = parsed.pathname.slice(1).split('/')[0];
      else {
        const pathMatch = parsed.pathname.match(/^\/(shorts|embed|live|v)\/([^/?]+)/);
        if (pathMatch) videoId = pathMatch[2];
      }
    } catch {}
  }
  return videoId;
})()

(async () => {
  const videoId = '${{ pipeline[0] }}';
  const lang = '${{ args.lang }}' || '';
  const cfg = window.ytcfg?.data_ || {};
  const apiKey = cfg.INNERTUBE_API_KEY;
  if (!apiKey) throw new Error('INNERTUBE_API_KEY not found');
  const resp = await fetch('/youtubei/v1/player?key=' + apiKey + '&prettyPrint=false', {
    method: 'POST',
    credentials: 'include',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      context: { client: { clientName: 'ANDROID', clientVersion: '20.10.38' } },
      videoId
    })
  });
  if (!resp.ok) throw new Error('InnerTube player API returned HTTP ' + resp.status);
  const data = await resp.json();
  const renderer = data.captions?.playerCaptionsTracklistRenderer;
  if (!renderer?.captionTracks?.length) throw new Error('No captions available');
  const tracks = renderer.captionTracks;
  let track = null;
  if (lang) {
    track = tracks.find(t => t.languageCode === lang) || tracks.find(t => t.languageCode.startsWith(lang));
  }
  if (!track) track = tracks.find(t => t.kind !== 'asr') || tracks[0];
  const captionResp = await fetch(track.baseUrl);
  const xml = await captionResp.text();
  if (!xml?.length) throw new Error('Caption URL returned empty response');
  function getAttr(tag, name) {
    const needle = name + '="';
    const idx = tag.indexOf(needle);
    if (idx === -1) return '';
    const valStart = idx + needle.length;
    const valEnd = tag.indexOf('"', valStart);
    return valEnd === -1 ? '' : tag.substring(valStart, valEnd);
  }
  function decodeEntities(s) {
    return s.replaceAll('&amp;', '&').replaceAll('&lt;', '<').replaceAll('&gt;', '>').replaceAll('&quot;', '"').replaceAll('&#39;', "'");
  }
  const isFormat3 = xml.includes('<p t="');
  const marker = isFormat3 ? '<p ' : '<text ';
  const endMarker = isFormat3 ? '</p>' : '</text>';
  const results = [];
  let pos = 0;
  while (true) {
    const tagStart = xml.indexOf(marker, pos);
    if (tagStart === -1) break;
    let contentStart = xml.indexOf('>', tagStart);
    if (contentStart === -1) break;
    contentStart += 1;
    const tagEnd = xml.indexOf(endMarker, contentStart);
    if (tagEnd === -1) break;
    const attrStr = xml.substring(tagStart + marker.length, contentStart - 1);
    const content = xml.substring(contentStart, tagEnd);
    let startSec, durSec;
    if (isFormat3) {
      startSec = (parseFloat(getAttr(attrStr, 't')) || 0) / 1000;
      durSec = (parseFloat(getAttr(attrStr, 'd')) || 0) / 1000;
    } else {
      startSec = parseFloat(getAttr(attrStr, 'start')) || 0;
      durSec = parseFloat(getAttr(attrStr, 'dur')) || 0;
    }
    const text = decodeEntities(content.replace(/<[^>]+>/g, '')).split('\\n').join(' ').trim();
    if (text) results.push({ start: startSec, end: startSec + durSec, text });
    pos = tagEnd + endMarker.length;
  }
  return results.map((seg, i) => ({
    index: i + 1,
    start: Number(seg.start).toFixed(2) + 's',
    end: Number(seg.end).toFixed(2) + 's',
    text: seg.text
  }));
})()
